'use client';

import { useEffect, useMemo, useState } from 'react';
import { useParams } from 'next/navigation';
import {
  completeExternalAcademicInvite,
  getExternalAcademicInvite,
  type ExternalAcademicProfilePayload,
  type ExternalIdentifierType,
} from '@/lib/api';

const identifierTypes: ExternalIdentifierType[] = ['SA_ID', 'PASSPORT', 'OTHER'];

export default function ExternalAcademicInvitePage() {
  const params = useParams<{ token: string }>();
  const token = useMemo(() => String(params?.token ?? ''), [params]);

  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [info, setInfo] = useState<string | null>(null);
  const [prefillEmail, setPrefillEmail] = useState('');
  const [role, setRole] = useState('external academic');

  const [form, setForm] = useState<ExternalAcademicProfilePayload>({
    title: '',
    first_name: '',
    middle_names: '',
    preferred_name: '',
    last_name: '',
    highest_qualification: '',
    email: '',
    alternate_email: '',
    preferred_contact_method: '',
    address: '',
    city: '',
    province_state: '',
    postal_code: '',
    country: '',
    phone: '',
    affiliation_institution: '',
    affiliation_department: '',
    affiliation_position_title: '',
    orcid: '',
    website_url: '',
    google_scholar_url: '',
    scopus_id: '',
    expertise_keywords: '',
    identifier_type: 'SA_ID',
    identifier_value: '',
  });

  useEffect(() => {
    if (!token) return;
    setLoading(true);
    setError(null);
    void getExternalAcademicInvite(token)
      .then((invite) => {
        setPrefillEmail(invite.email);
        setForm((prev) => ({ ...prev, email: invite.email }));
        setRole(invite.role.replace('_', ' '));
      })
      .catch((requestError) => {
        setError(requestError instanceof Error ? requestError.message : 'Failed to load invite');
      })
      .finally(() => setLoading(false));
  }, [token]);

  async function handleSubmit(event: React.FormEvent<HTMLFormElement>) {
    event.preventDefault();
    if (!token) return;
    setSubmitting(true);
    setError(null);
    setInfo(null);
    try {
      await completeExternalAcademicInvite(token, form);
      setInfo('Profile submitted successfully. Thank you, your details have been saved and linked to the workflow case.');
    } catch (requestError) {
      setError(requestError instanceof Error ? requestError.message : 'Failed to submit profile');
    } finally {
      setSubmitting(false);
    }
  }

  if (loading) {
    return <main className='mx-auto max-w-3xl px-6 py-12 text-sm text-slate-600'>Loading invite...</main>;
  }

  return (
    <main className='mx-auto max-w-3xl px-6 py-10'>
      <h1 className='text-2xl font-semibold text-slate-900'>UWC External Academic Profile</h1>
      <p className='mt-2 text-sm text-slate-600'>You were invited to complete your details for the role: <span className='font-medium'>{role}</span>.</p>
      {prefillEmail ? <p className='mt-1 text-sm text-slate-600'>Invite email: {prefillEmail}</p> : null}

      {error ? <p className='mt-4 rounded-md bg-red-50 px-3 py-2 text-sm text-red-700'>{error}</p> : null}
      {info ? <p className='mt-4 rounded-md bg-emerald-50 px-3 py-2 text-sm text-emerald-700'>{info}</p> : null}

      <form className='mt-6 grid grid-cols-1 gap-3 md:grid-cols-2' onSubmit={handleSubmit}>
        <label className='text-sm'>Title<input className='mt-1 w-full rounded border px-3 py-2' value={form.title} onChange={(e) => setForm({ ...form, title: e.target.value })} required /></label>
        <label className='text-sm'>First name<input className='mt-1 w-full rounded border px-3 py-2' value={form.first_name} onChange={(e) => setForm({ ...form, first_name: e.target.value })} required /></label>
        <label className='text-sm'>Middle names<input className='mt-1 w-full rounded border px-3 py-2' value={form.middle_names ?? ''} onChange={(e) => setForm({ ...form, middle_names: e.target.value })} /></label>
        <label className='text-sm'>Preferred name<input className='mt-1 w-full rounded border px-3 py-2' value={form.preferred_name ?? ''} onChange={(e) => setForm({ ...form, preferred_name: e.target.value })} /></label>
        <label className='text-sm'>Surname<input className='mt-1 w-full rounded border px-3 py-2' value={form.last_name} onChange={(e) => setForm({ ...form, last_name: e.target.value })} required /></label>
        <label className='text-sm'>Highest qualification<input className='mt-1 w-full rounded border px-3 py-2' value={form.highest_qualification} onChange={(e) => setForm({ ...form, highest_qualification: e.target.value })} required /></label>

        <label className='text-sm'>Identifier type
          <select className='mt-1 w-full rounded border px-3 py-2' value={form.identifier_type} onChange={(e) => setForm({ ...form, identifier_type: e.target.value as ExternalIdentifierType })}>
            {identifierTypes.map((type) => <option key={type} value={type}>{type}</option>)}
          </select>
        </label>
        <label className='text-sm'>ID / Passport / Other unique number<input className='mt-1 w-full rounded border px-3 py-2' value={form.identifier_value} onChange={(e) => setForm({ ...form, identifier_value: e.target.value })} required /></label>

        <label className='text-sm'>Primary email<input className='mt-1 w-full rounded border px-3 py-2' type='email' value={form.email} onChange={(e) => setForm({ ...form, email: e.target.value })} required /></label>
        <label className='text-sm'>Alternate email<input className='mt-1 w-full rounded border px-3 py-2' type='email' value={form.alternate_email ?? ''} onChange={(e) => setForm({ ...form, alternate_email: e.target.value })} /></label>
        <label className='text-sm'>Phone<input className='mt-1 w-full rounded border px-3 py-2' value={form.phone ?? ''} onChange={(e) => setForm({ ...form, phone: e.target.value })} /></label>
        <label className='text-sm'>Preferred contact method<input className='mt-1 w-full rounded border px-3 py-2' value={form.preferred_contact_method ?? ''} onChange={(e) => setForm({ ...form, preferred_contact_method: e.target.value })} /></label>

        <label className='text-sm md:col-span-2'>Address<input className='mt-1 w-full rounded border px-3 py-2' value={form.address} onChange={(e) => setForm({ ...form, address: e.target.value })} required /></label>
        <label className='text-sm'>City<input className='mt-1 w-full rounded border px-3 py-2' value={form.city ?? ''} onChange={(e) => setForm({ ...form, city: e.target.value })} /></label>
        <label className='text-sm'>Province/State<input className='mt-1 w-full rounded border px-3 py-2' value={form.province_state ?? ''} onChange={(e) => setForm({ ...form, province_state: e.target.value })} /></label>
        <label className='text-sm'>Postal code<input className='mt-1 w-full rounded border px-3 py-2' value={form.postal_code ?? ''} onChange={(e) => setForm({ ...form, postal_code: e.target.value })} /></label>
        <label className='text-sm'>Country<input className='mt-1 w-full rounded border px-3 py-2' value={form.country} onChange={(e) => setForm({ ...form, country: e.target.value })} required /></label>

        <label className='text-sm'>Institution<input className='mt-1 w-full rounded border px-3 py-2' value={form.affiliation_institution ?? ''} onChange={(e) => setForm({ ...form, affiliation_institution: e.target.value })} /></label>
        <label className='text-sm'>Department<input className='mt-1 w-full rounded border px-3 py-2' value={form.affiliation_department ?? ''} onChange={(e) => setForm({ ...form, affiliation_department: e.target.value })} /></label>
        <label className='text-sm'>Position title<input className='mt-1 w-full rounded border px-3 py-2' value={form.affiliation_position_title ?? ''} onChange={(e) => setForm({ ...form, affiliation_position_title: e.target.value })} /></label>
        <label className='text-sm'>ORCID<input className='mt-1 w-full rounded border px-3 py-2' value={form.orcid ?? ''} onChange={(e) => setForm({ ...form, orcid: e.target.value })} /></label>

        <label className='text-sm md:col-span-2'>Expertise keywords (comma-separated)<input className='mt-1 w-full rounded border px-3 py-2' value={form.expertise_keywords ?? ''} onChange={(e) => setForm({ ...form, expertise_keywords: e.target.value })} /></label>

        <label className='text-sm'>Website URL<input className='mt-1 w-full rounded border px-3 py-2' value={form.website_url ?? ''} onChange={(e) => setForm({ ...form, website_url: e.target.value })} /></label>
        <label className='text-sm'>Google Scholar URL<input className='mt-1 w-full rounded border px-3 py-2' value={form.google_scholar_url ?? ''} onChange={(e) => setForm({ ...form, google_scholar_url: e.target.value })} /></label>
        <label className='text-sm md:col-span-2'>Scopus ID<input className='mt-1 w-full rounded border px-3 py-2' value={form.scopus_id ?? ''} onChange={(e) => setForm({ ...form, scopus_id: e.target.value })} /></label>

        <div className='mt-2 md:col-span-2'>
          <button type='submit' className='rounded bg-slate-900 px-4 py-2 text-sm text-white disabled:opacity-60' disabled={submitting}>{submitting ? 'Submitting...' : 'Submit profile'}</button>
        </div>
      </form>
    </main>
  );
}
